// Quil OpenCode session tracker — AUTO-GENERATED by the Quil daemon.
//
// Tracks opencode session-id rotation (new session, /new, fork, compaction)
// by writing the current session id to $QUIL_HOME/sessions/opencode-<paneID>.id.
// The daemon consults that file on pane restore to decide between
// `--session <id>` (resume exact conversation) and `--continue` (fallback).
//
// Loaded by opencode via OPENCODE_CONFIG_CONTENT when Quil spawns an opencode
// pane. When QUIL_PANE_ID is absent (opencode invoked outside Quil) the
// plugin is a no-op. Safe to delete — Quil recreates it on next daemon start.

import { writeFile, rename, mkdir, unlink, appendFile } from "node:fs/promises";
import { join } from "node:path";
import { randomUUID } from "node:crypto";

const PANE_ID_RE = /^[A-Za-z0-9_-]{1,64}$/;
const SESSION_ID_RE = /^[0-9a-zA-Z_-]{1,128}$/;

export default async function quilSessionTracker(_input) {
  const paneId = process.env.QUIL_PANE_ID || "";
  const quilHome = process.env.QUIL_HOME || "";
  if (!paneId || !quilHome) return {};
  if (!PANE_ID_RE.test(paneId)) return {};
  // Defense-in-depth: the daemon controls QUIL_HOME but a leaked/forwarded
  // env from a hostile parent could still contain a NUL terminator that
  // truncates the path silently on some platforms. Bail before constructing
  // any filesystem paths.
  if (quilHome.includes("\0")) return {};

  const sessionsDir = join(quilHome, "sessions");
  const logDir = join(quilHome, "opencodehook");
  const logFile = join(logDir, "hook.log");
  const target = join(sessionsDir, "opencode-" + paneId + ".id");
  // Cap hook.log at this size so a misbehaving opencode flooding events
  // (or a hostile config) cannot fill the disk. We rotate by renaming the
  // current log to .1 once over the threshold; older history is discarded.
  const LOG_SIZE_CAP_BYTES = 1 * 1024 * 1024;

  const logLine = async (msg) => {
    try {
      await mkdir(logDir, { recursive: true });
      // Best-effort size cap: stat then rotate when over threshold. The
      // race between stat and append is fine — worst case we exceed the cap
      // by one tick of writes.
      try {
        const { stat } = await import("node:fs/promises");
        const st = await stat(logFile);
        if (st.size > LOG_SIZE_CAP_BYTES) {
          await rename(logFile, logFile + ".1");
        }
      } catch (_) { /* file may not exist yet */ }
      const line = new Date().toISOString() + " pane=" + paneId + " " + msg + "\n";
      await appendFile(logFile, line);
    } catch (_) { /* never throw from logger */ }
  };

  // De-dupe by remembering the last id we recorded. opencode fires
  // session.updated repeatedly with the same id during a single response;
  // without this guard we would do N writes + N log lines per turn.
  let lastRecorded = null;

  const record = async (sessionId, eventType) => {
    // typeof guard: if the bus payload ever surfaces a non-string id (number,
    // object) the regex .test() would coerce via String() — narrower to bail
    // here so we never write a coerced string to the file.
    if (typeof sessionId !== "string" || !SESSION_ID_RE.test(sessionId)) {
      const shown = sessionId == null ? "(empty)" : String(sessionId).slice(0, 200);
      await logLine("rejected session_id: " + shown + " (type=" + eventType + ")");
      return;
    }
    if (sessionId === lastRecorded) return;
    try {
      await mkdir(sessionsDir, { recursive: true });
      const tmp = target + "." + process.pid + "." + randomUUID() + ".tmp";
      await writeFile(tmp, sessionId);
      await rename(tmp, target);
      lastRecorded = sessionId;
      await logLine("recorded " + eventType + " session=" + sessionId);
    } catch (e) {
      await logLine("write failed: " + (e && e.message ? e.message : String(e)));
    }
  };

  const clear = async () => {
    try { await unlink(target); } catch (_) { /* may not exist */ }
    lastRecorded = null;
    await logLine("cleared (session.deleted)");
  };

  // The Hooks contract is returned directly — NOT wrapped under a `hooks:`
  // key. See ~/.config/opencode/node_modules/@opencode-ai/plugin/dist/index.d.ts
  // (`export interface Hooks { event?: ... }`). The generic `event` hook
  // receives every bus event; we filter by `event.type` and extract the
  // session id.
  //
  // Payload shape: opencode 1.14.x runtime emits `properties.sessionID`
  // directly on every session.* event. The @opencode-ai/sdk type defs
  // (types.gen.d.ts) describe session.created/.updated/.deleted as carrying
  // `properties.info: Session` with no top-level sessionID. We accept either
  // form to survive bus payload churn between opencode releases — if a
  // future version drops the runtime sessionID and reverts to the typed
  // shape, tracking continues to work.
  return {
    event: async ({ event }) => {
      try {
        const t = event && event.type;
        if (!t || !t.startsWith("session.")) return;
        const props = event.properties || {};
        const sid = props.sessionID || (props.info && props.info.id);
        switch (t) {
          case "session.created":
          case "session.updated":
          case "session.idle":
          case "session.compacted":
            await record(sid, t);
            break;
          case "session.deleted":
            await clear();
            break;
        }
      } catch (e) {
        await logLine("event handler error: " + (e && e.message ? e.message : String(e)));
      }
    },
  };
}
